/**
 * Get converter function by page slug
 */
export function getPageConverter(slug: string): (() => SectionConfig[]) | null {
  const converters: Record<string, () => SectionConfig[]> = {
    '/en/app-builder': convertAppBuilderPage,
    '/ar/app-builder': convertAppBuilderPage,
    '/en': convertHomePage,
    '/ar': convertHomePage,
  };

  return converters[slug] || null;
}